// Server-side validation — mirrors hospital-form/index.html and expands one item per doctor.
const body = $input.first().json.body || $input.first().json;

const FACILITY_TYPES = [
  'General Hospital',
  'Multi-specialty Clinic',
  'Dental Clinic',
  'Pathology Lab',
  'Diagnostic Center',
  'Physiotherapy Clinic',
  'Eye Clinic',
  'ENT Clinic',
  'Other Medical Facility',
];

const clean = (value, max = 1000) => String(value || '').trim().slice(0, max);
const normalizeUsername = value => clean(value, 80).toLowerCase();
const usernameToInternalEmail = username => normalizeUsername(username) + '@auth.vaitalcare.local';
const hospital_name = clean(body.hospital_name, 200);
const facility_type = clean(body.facility_type, 80);
const address = clean(body.address, 1000);
const city = clean(body.city, 120);
const contact_phone = clean(body.contact_phone, 20).replace(/\s+/g, '');
const admin_contact_name = clean(body.admin_contact_name, 150);
const clinic_logo_url = clean(body.clinic_logo_url, 1000);
const clinic_email = clean(body.clinic_email, 254);
const clinic_website = clean(body.clinic_website, 1000);
const consultation_hours = clean(body.consultation_hours, 200);
const errors = [];
const isUrl = value => /^https:\/\//i.test(value);

function rateLimitRequest(scope, key, limit, windowMs) {
  if (!key) return null;
  try {
    const store = typeof $getWorkflowStaticData === 'function' ? $getWorkflowStaticData('global') : null;
    if (!store) return null;
    store._rateLimits = store._rateLimits || {};
    const now = Date.now();
    const bucketKey = scope + ':' + key;
    const bucket = Array.isArray(store._rateLimits[bucketKey]) ? store._rateLimits[bucketKey] : [];
    const recent = bucket.filter(ts => now - ts < windowMs);
    recent.push(now);
    store._rateLimits[bucketKey] = recent;
    return recent.length > limit ? Math.ceil((windowMs - (now - recent[0])) / 1000) : null;
  } catch (_) {
    return null;
  }
}

const headers = $input.first().json.headers || {};
const header = name => headers[name] || headers[name.toLowerCase()] || headers[name.toUpperCase()] || '';
const clientIp = String(header('x-forwarded-for') || header('x-real-ip') || 'unknown').split(',')[0].trim();
const ipRetryAfter = rateLimitRequest('hospital-boarding-ip', clientIp, 40, 60 * 60 * 1000);
const phoneRetryAfter = contact_phone ? rateLimitRequest('hospital-boarding-contact', contact_phone, 6, 60 * 60 * 1000) : null;
if (ipRetryAfter || phoneRetryAfter) errors.push('too_many_requests: please wait before submitting again');

let doctors = [];
try {
  doctors = body.doctors_json ? JSON.parse(String(body.doctors_json)) : [];
} catch (_) {
  errors.push('doctors_json: must be valid JSON');
}
if (!Array.isArray(doctors) || doctors.length === 0) {
  doctors = [{
    doctor_name: body.doctor_name,
    doctor_qualification: body.doctor_qualification,
    doctor_expertise: body.doctor_expertise,
    doctor_registration_number: body.doctor_registration_number,
    doctor_phone: body.doctor_phone,
    doctor_signature_url: body.doctor_signature_url,
    login_username: body.login_username,
    password: body.password,
  }];
}

doctors = doctors.slice(0, 10).map((doctor, index) => ({
  doctor_index: index + 1,
  doctor_name: clean(doctor.doctor_name, 150),
  doctor_qualification: clean(doctor.doctor_qualification, 200) || null,
  doctor_expertise: clean(doctor.doctor_expertise, 500),
  doctor_registration_number: clean(doctor.doctor_registration_number, 120),
  doctor_phone: clean(doctor.doctor_phone, 20).replace(/\s+/g, '') || null,
  doctor_signature_url: clean(doctor.doctor_signature_url, 1000) || null,
  login_username: normalizeUsername(doctor.login_username),
  auth_email: usernameToInternalEmail(doctor.login_username),
  _password: String(doctor.password || ''),
}));

if (!hospital_name || hospital_name.length < 2) errors.push('hospital_name: required, minimum 2 characters');
if (!FACILITY_TYPES.includes(facility_type)) errors.push('facility_type: required, must be a supported facility type');
if (!address || address.length < 5) errors.push('address: required, minimum 5 characters');
if (!city || city.length < 2) errors.push('city: required, minimum 2 characters');
if (!/^\+?[1-9]\d{6,14}$/.test(contact_phone)) errors.push('contact_phone: required, must be a valid phone number');
if (!admin_contact_name || admin_contact_name.length < 2) errors.push('admin_contact_name: required, minimum 2 characters');
if (clinic_logo_url && !isUrl(clinic_logo_url)) errors.push('clinic_logo_url: must be an HTTPS URL');
if (clinic_email && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(clinic_email)) errors.push('clinic_email: must be a valid email address');
if (clinic_website && !isUrl(clinic_website)) errors.push('clinic_website: must be an HTTPS URL');
if (!consultation_hours || consultation_hours.length < 2) errors.push('consultation_hours: required, minimum 2 characters');

const seenUsernames = new Set();
for (const doctor of doctors) {
  const prefix = 'doctor_' + doctor.doctor_index;
  if (!doctor.doctor_name || doctor.doctor_name.length < 2) errors.push(prefix + '_name: required, minimum 2 characters');
  if (doctor.doctor_qualification && doctor.doctor_qualification.length < 2) errors.push(prefix + '_qualification: minimum 2 characters when provided');
  if (!doctor.doctor_expertise || doctor.doctor_expertise.length < 2) errors.push(prefix + '_expertise: required, minimum 2 characters');
  if (!doctor.doctor_registration_number || doctor.doctor_registration_number.length < 2) errors.push(prefix + '_registration_number: required, minimum 2 characters');
  if (doctor.doctor_phone && !/^\+?[1-9]\d{6,14}$/.test(doctor.doctor_phone)) errors.push(prefix + '_phone: must be a valid phone number');
  if (doctor.doctor_signature_url && !isUrl(doctor.doctor_signature_url)) errors.push(prefix + '_signature_url: must be an HTTPS URL');
  if (!/^[a-z0-9._-]{3,80}$/.test(doctor.login_username)) errors.push(prefix + '_username: required, use lowercase letters, numbers, dot, underscore, or hyphen');
  if (seenUsernames.has(doctor.login_username)) errors.push(prefix + '_username: duplicate username in this clinic submission');
  seenUsernames.add(doctor.login_username);
  if (!doctor._password || doctor._password.length < 8) errors.push(prefix + '_password: required, minimum 8 characters');
}

if (errors.length > 0) return [{ json: { _valid: false, _errors: errors } }];

return doctors.map(doctor => ({
  json: {
    _valid: true,
    _errors: [],
    hospital_name,
    facility_type,
    address,
    city,
    contact_phone,
    admin_contact_name,
    clinic_logo_url: clinic_logo_url || null,
    clinic_email: clinic_email || null,
    clinic_website: clinic_website || null,
    consultation_hours,
    doctor_count: doctors.length,
    ...doctor,
  }
}));

// Build one Twilio send item per recipient: clinic contact_phone and doctor_phone (if distinct).
const row = $('Insert Hospital Row').first().json;
const form = $json;
const tz = $env.TIMEZONE || 'Asia/Kolkata';
const scheduledDate = new Date().toLocaleDateString('en-CA', { timeZone: tz });
const contentSid = $env.TWILIO_CONTENT_HOSPITAL_ONBOARDING || '';

function toE164(raw) {
  const p = String(raw || '').trim().replace(/\s+/g, '');
  if (!p) return '';
  if (/^\+[1-9]\d{6,14}$/.test(p)) return p;
  if (/^[0-9]{10}$/.test(p)) return '+91' + p;
  if (/^[1-9]\d{6,14}$/.test(p)) return '+' + p;
  return '';
}

const hospital = String(row.hospital_name || form.hospital_name || '').trim();
const facility = String(row.facility_type || form.facility_type || '').trim();
const doctor = String(row.doctor_name || form.doctor_name || '').trim();
const city = String(row.city || form.city || '').trim();
const boardingId = String(row.id || '').trim();
const clinicId = String(row.clinic_id || form.clinic_id || '').trim();
if (!clinicId || !/^[0-9a-f-]{36}$/i.test(clinicId)) {
  return [{ json: { _skip: true, reason: 'Invalid clinic_id after hospital onboarding insert', boardingId } }];
}
const contentVars = JSON.stringify({ '1': hospital, '2': facility, '3': doctor, '4': city });
const messageBody = 'Hi ' + hospital + ', your onboarding for ' + facility + ' is complete. We have registered ' + doctor + ' as a dashboard user and ' + city + ' as the facility location.';

const targets = [
  { role: 'clinic', phone: toE164(row.contact_phone || form.contact_phone) },
  { role: 'doctor', phone: toE164(row.doctor_phone || form.doctor_phone) },
];
const seen = new Set();
const out = [];
for (const t of targets) {
  if (!t.phone || seen.has(t.phone)) continue;
  seen.add(t.phone);
  out.push({
    json: {
      _skip: false,
      _recipient_role: t.role,
      _boarding_id: boardingId,
      _phone: t.phone,
      _to_phone: 'whatsapp:' + t.phone,
      _clinic_id: clinicId,
      clinic_id: clinicId,
      _hospital_name: hospital,
      hospital_name: hospital,
      _facility_type: facility,
      _doctor_name: doctor,
      _city: city,
      _message_type: 'hospital_onboarding',
      _scheduled_date: scheduledDate,
      _content_sid: contentSid,
      _content_variables: contentVars,
      _message_body: messageBody,
    },
  });
}
if (out.length === 0) {
  return [{ json: { _skip: true, reason: 'No valid WhatsApp recipients', boardingId, clinic_id: clinicId } }];
}
return out;

// Create one Supabase Auth user per validated doctor. Passwords are used only in this server-side Admin API call.
const supabaseUrl = String($env.SUPABASE_URL || '').replace(/\/+$/, '');
const serviceRoleKey = String($env.SUPABASE_SERVICE_ROLE_KEY || '');
if (!supabaseUrl || !serviceRoleKey) throw new Error('SUPABASE_URL and SUPABASE_SERVICE_ROLE_KEY are required for doctor account creation');

const output = [];
for (const item of $input.all()) {
  const data = item.json;
  const password = data._password;
  if (!password) throw new Error('Password missing for ' + data.login_username);

  const payload = {
    email: data.auth_email,
    password,
    email_confirm: true,
    user_metadata: {
      login_username: data.login_username,
      role: 'doctor',
      doctor_name: data.doctor_name,
      clinic_name: data.hospital_name,
    },
  };

  const response = await fetch(supabaseUrl + '/auth/v1/admin/users', {
    method: 'POST',
    headers: {
      apikey: serviceRoleKey,
      Authorization: 'Bearer ' + serviceRoleKey,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(payload),
  });

  let authUser = {};
  try { authUser = await response.json(); } catch (_) {}
  const duplicate = response.status === 422 || /already|registered|exists/i.test(JSON.stringify(authUser));
  if (!response.ok && !duplicate) {
    throw new Error('Could not create dashboard account for username ' + data.login_username);
  }

  if (duplicate) {
    const lookup = await fetch(supabaseUrl + '/auth/v1/admin/users?email=' + encodeURIComponent(data.auth_email), {
      headers: { apikey: serviceRoleKey, Authorization: 'Bearer ' + serviceRoleKey },
    });
    let lookupBody = {};
    try { lookupBody = await lookup.json(); } catch (_) {}
    const users = Array.isArray(lookupBody.users) ? lookupBody.users : (Array.isArray(lookupBody) ? lookupBody : []);
    authUser = users.find(user => String(user.email || '').toLowerCase() === data.auth_email) || authUser;
  }

  if (!authUser.id) throw new Error('Dashboard account exists but could not resolve auth user id for ' + data.login_username);
  const { _password, ...safeData } = data;
  output.push({ json: { ...safeData, auth_user_id: authUser.id } });
}
return output;
